class Solution:
    def numMatchingSubseq(self, s: str, words: List[str]) -> int:
        buckets = defaultdict(list)
        for w in words:
            buckets[w[0]].append([w, 0])
        ans = 0
        for c in s:
            nxt = []
            for w, i in buckets.get(c, []):
                i += 1
                if i == len(w): ans += 1
                else: nxt.append([w, i])
            buckets[c] = nxt
        return ans

