class Solution {
public:
    int numMatchingSubseq(string s, vector<string>& words) {
        vector<vector<pair<string,int>>> buck(26);
        for(auto& w:words) buck[w[0]-'a'].push_back({w,0});
        int ans=0;
        for(char c:s){
            auto cur=buck[c-'a']; buck[c-'a'].clear();
            for(auto [w,i]:cur){
                i++;
                if(i==(int)w.size()) ans++;
                else buck[w[i]-'a'].push_back({w,i});
            }
        }
        return ans;
    }
};

