int numMatchingSubseq(char* s, char** words, int n) {
    int ans=0; for(int i=0;i<n;i++){ char* w=words[i]; int j=0; for(char* p=s;*p&&w[j];p++) if(*p==w[j]) j++; if(!w[j]) ans++; } return ans;
}
